new_feature_requests.summary:
Add the following temporary public shared function to the backend main actor, without modifying any existing logic, data structures, or other functions:

```motoko
public shared ({ caller }) func forceSetMeAsSuperAdmin() : async Text {
  let updated = adminStore.map(
    func((principal, record)) {
      if (principal == caller) {
        (principal, { record with role = #super_admin });
      } else {
        (principal, record);
      }
    }
  );
  adminStore := updated;
  return "Role updated to super_admin for caller";
};
```
